```scala
import zio._
import zio.console.{ PutStrLn, Utf8 }

object Main extends App {
  val io = for {
    putStrLn <- PutStrLn("Enter a number: ")
    input   <- readLine
    result  <- ZIO.fromString(input).map(_.toInt)
  } yield s"$result is an integer!"

  io.provideLayer(Utf8.utf8)
}
```

